import asyncio
from typing import Any

async def run_tools_parallel(
    tool_calls: list[dict],
) -> list[dict]:
    """Run all tool calls concurrently; return partial results on individual failures."""
    async def run_one(tc: dict) -> dict:
        try:
            result = await execute_tool(tc["name"], tc["input"])
            return {"id": tc["id"], "name": tc["name"], "success": True, "result": result}
        except asyncio.TimeoutError:
            return {"id": tc["id"], "name": tc["name"], "success": False,
                    "error": "timeout", "message": f"{tc['name']} timed out after 10s"}
        except Exception as e:
            return {"id": tc["id"], "name": tc["name"], "success": False,
                    "error": type(e).__name__, "message": str(e)[:200]}

    tasks = [asyncio.create_task(asyncio.wait_for(run_one(tc), timeout=10.0))
             for tc in tool_calls]
    results = await asyncio.gather(*tasks, return_exceptions=True)
    # Replace exceptions with error dicts
    return [
        r if isinstance(r, dict)
        else {"id": tool_calls[i]["id"], "name": tool_calls[i]["name"],
              "success": False, "error": "unexpected", "message": str(r)}
        for i, r in enumerate(results)
    ]

