import time

class CircuitBreaker:
    """Simple circuit breaker: open after N failures, reset after cooldown."""

    def __init__(self, failure_threshold: int = 5, cooldown_s: float = 60.0):
        self.threshold = failure_threshold
        self.cooldown = cooldown_s
        self._failures = 0
        self._opened_at: float | None = None

    @property
    def is_open(self) -> bool:
        if self._opened_at is None:
            return False
        if time.time() - self._opened_at > self.cooldown:
            # Half-open: allow one probe
            self._opened_at = None
            self._failures = 0
            return False
        return True

    def record_failure(self):
        self._failures += 1
        if self._failures >= self.threshold:
            self._opened_at = time.time()

    def record_success(self):
        self._failures = 0
        self._opened_at = None

# Usage:
breaker = CircuitBreaker(failure_threshold=5, cooldown_s=60.0)

async def call_with_circuit_breaker(messages: list) -> str:
    if breaker.is_open:
        return "Service is temporarily unavailable. Please try again in a minute."
    try:
        resp = await client.messages.create(
            model="claude-opus-4-8", max_tokens=2048, messages=messages
        )
        breaker.record_success()
        return resp.content[0].text
    except Exception as e:
        breaker.record_failure()
        raise

// GracefulDegradationBanner.tsx - shown when running in degraded mode
export function DegradedModeBanner({ tier }: { tier: "degraded" | "offline" }) {
  if (tier === "offline") {
    return (
      <div className="flex items-center gap-2 bg-red-950 border border-red-800
                      rounded-lg px-3 py-2 text-xs text-red-300 mb-2">
        <span>&#9679;</span>
        Service unavailable. Showing cached response.
      </div>
    );
  }
  return (
    <div className="flex items-center gap-2 bg-amber-950 border border-amber-700
                    rounded-lg px-3 py-2 text-xs text-amber-300 mb-2">
      <span>&#9651;</span>
      Running in reduced mode: tool use is temporarily disabled.
    </div>
  );
}

// PartialResultsNotice.tsx - inline notice when some tools failed
export function PartialResultsNotice({ failed }: { failed: string[] }) {
  if (failed.length === 0) return null;
  return (
    <p className="text-xs text-amber-400 mt-1">
      Note: {failed.join(", ")} {failed.length === 1 ? "was" : "were"} unavailable.
      Results may be incomplete.
    </p>
  );
}
